class Solution:
    def countBeautifulPairs(self, nums: List[int]) -> int:
        count = 0
        n = len(nums)
        for i in range(n):
            first_digit = int(str(nums[i])[0])
            for j in range(i + 1, n):
                last_digit = int(str(nums[j])[-1])
                if self.gcd(first_digit, last_digit) == 1:
                    count += 1
        return count

    def gcd(self, x: int, y: int) -> int:
        while y:
            x, y = y, x % y
        return x
